    export function useAuth() {
    const [session, setSession] = useState(null);
    const [staffProfile, setStaffProfile] = useState(null);
    const [loading, setLoading] = useState(true);
    useEffect(() => {
    import(". / supabase ").then(async ({ getSession, getStaffByUserId, supabase }) => {
    const s = await getSession();
    setSession(s);
    if (s?.user) {
    const p = await getStaffByUserId(s.user.id);
    setStaffProfile(p);
    }
    setLoading(false);
    supabase.auth.onAuthStateChange(async (_e, s) => {
    setSession(s);
    if (s?.user) {
    const p = await getStaffByUserId(s.user.id);
    setStaffProfile(p);
    } else {
    setStaffProfile(null);
    }
    });
    });
    }, []);
    return { session, staffProfile, loading, isAdmin: staffProfile?.is_admin };
    }
    export function Avatar({ name=" ? ", size=38, color, photoUrl }) {
         const palette = [" #d4af37 "," #c9a961 "," #a8852a "," #9b7d3a "," #bfa05a "];
         const bg = color || palette[(name.charCodeAt(0)||0) % palette.length];
         const initials = name.includes(" ") ? name.split(" ").map(w=>w[0]).join(" ").slice(0,2) : name.slice(0,2);
         if (photoUrl) return <img src={photoUrl} alt={name} style={{ width:size, height:size, borderRadius:size*.28, objectFit:" cover ", flexShrink:0, border:`1px solid ${bg}40` }} />;
         return <div style={{ width:size, height:size, borderRadius:size*.28, background:`${bg}22`, display:" flex ", alignItems:" center ", justifyContent:" center ", fontSize:size*.36, fontWeight:700, color:bg, flexShrink:0, fontFamily:" 'Cormorant Garamond', serif ", border:`1px solid ${bg}28` }}>{initials.toUpperCase()}</div>;
}
